function LFightIdlePathAction:OnRun(time)
	local actor = self._obj:GetPathActor()
	if self._bInitStart then
		if(actor:IsPathing()) then return end
		self:ResetDefaultAction()
	else
		if(actor:IsPathing()) then return end
		self:StartPath()
	end
end
