function LFightIdlePathAction:StartPathToBoard(toBoardRefId)
	self._bInitStart = false
	self._targetBoardRefId = toBoardRefId
	local obj = self._obj
	obj:StopActor()
	local pathActor = obj:GetPathActor()
	if pathActor:IsPathing() and pathActor:IsJumping() then
		return
	end
	self:StartPath()
end

function LFightIdlePathAction:StartPath()
	self._bInitStart = true
	local obj = self._obj
	obj:SetStatus(LFightIdleConst.STATUS_PATH)
	obj:GetPathActor():StartPathing(self._targetBoardRefId)

